import SwiftUI
import Alamofire

struct Stock: Codable {
    let id: Int
    let name: String
    let currentPrice: Double
}

struct TradeRequest: Codable {
    let stockId: Int
    let quantity: Int
}

struct TransactionResponse: Codable {
    let status: String
    let transactionId: Int
}

struct ContentView: View {
    @State private var stocks = [Stock]()
    @State private var selectedStock: Stock? = nil
    @State private var quantity = 1
    @State private var errorMessage: String? = nil

    var body: some View {
        NavigationView {
            List {
                ForEach(stocks) { stock in
                    NavigationLink(destination: StockDetailView(stock: stock)) {
                        Text(stock.name)
                    }
                }
                .onAppear {
                    loadStocks()
                }
            }
            .navigationTitle("Portfolio")
            .sheet(item: $selectedStock) { stock in
                TradeView(stock: stock)
            }
        }
    }

    private func loadStocks() {
        AF.request("https://api.example.com/stocks").responseDecodable(of: [Stock].self) { response in
            switch response.result {
            case .success(let stocks):
                self.stocks = stocks
            case .failure(let error):
                print("Error loading stocks: \(error)")
            }
        }
    }

    struct StockDetailView: View {
        let stock: Stock

        var body: some View {
            Text("Details for \(stock.name)")
        }
    }

    struct TradeView: View {
        let stock: Stock

        @State private var quantity: Int = 1

        var body: some View {
            Form {
                Section(header: Text("Quantity")) {
                    Stepper("\(quantity)", value: $quantity, in: 1...100)
                }
                Button("Trade") {
                    trade(stock: stock, quantity: quantity)
                }
            }
        }

        private func trade(stock: Stock, quantity: Int) {
            let tradeRequest = TradeRequest(stockId: stock.id, quantity: quantity)
            AF.request("https://api.example.com/transactions", method: .post, parameters: ["trade": try! JSONEncoder().encode(tradeRequest)])
                .responseDecodable(of: TransactionResponse.self) { response in
                    switch response.result {
                    case .success(let transactionResponse):
                        if transactionResponse.status == "success" {
                            selectedStock = nil
                        } else {
                            errorMessage = transactionResponse.status
                        }
                    case .failure(let error):
                        print("Error trading: \(error)")
                    }
                }
        }
    }
}